package server

import (
	"context"
	"crypto/ed25519"
	"crypto/sha256"
	"fmt"
	"log/slog"
	"strings"
	"sync"
	"time"

	"github.com/relab/gorums"
	pb "github.com/Mekruba/gorums-benchmark/simplex.gorums/proto"
)

// delta is the assumed upper bound on network message delay.
// 50ms gives a 150ms backup timer, sufficient headroom for goroutine
// scheduling overhead under benchmark load on localhost.
const delta = 50 * time.Millisecond

// simplexNode implements the Simplex BFT consensus protocol and the
// pb.SimplexNodeServer gRPC interface generated by Gorums.
type simplexNode struct {
	id  uint32
	n   int
	cfg gorums.Configuration

	privKey ed25519.PrivateKey
	pubKeys map[uint32]ed25519.PublicKey

	mu     sync.Mutex
	ctx    context.Context
	cancel context.CancelFunc
	height uint64
	chain  []*pb.Notarization

	votes     map[uint64]map[string][]*pb.VoteMsg
	voted     map[uint64]bool
	finalizes map[uint64]map[uint32]bool
	finalized map[uint64]bool
	notarized map[uint64]*pb.Notarization

	timer      *time.Timer
	timerFired bool

	finalizedTxs map[uint64][]string

	pendingProposals map[uint64]*pb.ProposeMsg
	pendingVotes     map[uint64][]*pb.VoteMsg

	txMu   sync.Mutex
	txPool []string

	// proposedTxs[h] holds the txs drained from txPool when this node
	// proposed a block at height h. If a dummy block wins instead,
	// these txs are re-queued so they aren't lost.
	proposedTxs map[uint64][]string

	// In-process tx tracking for benchmark: txID → signal channel.
	pendingTxMu    sync.Mutex
	pendingTxs     map[string]chan struct{}
	finalizedTxSet map[string]struct{} // txs already finalized; prevents duplicate proposals
}

func newSimplexNode(id uint32, n int, cfg gorums.Configuration, privKey ed25519.PrivateKey, pubKeys map[uint32]ed25519.PublicKey) *simplexNode {
	ctx, cancel := context.WithCancel(context.Background())
	return &simplexNode{
		id:               id,
		n:                n,
		cfg:              cfg,
		privKey:          privKey,
		pubKeys:          pubKeys,
		ctx:              ctx,
		cancel:           cancel,
		height:           1,
		votes:            make(map[uint64]map[string][]*pb.VoteMsg),
		voted:            make(map[uint64]bool),
		finalizes:        make(map[uint64]map[uint32]bool),
		finalized:        make(map[uint64]bool),
		notarized:        make(map[uint64]*pb.Notarization),
		finalizedTxs:     make(map[uint64][]string),
		proposedTxs:      make(map[uint64][]string),
		pendingProposals: make(map[uint64]*pb.ProposeMsg),
		pendingVotes:     make(map[uint64][]*pb.VoteMsg),
		pendingTxs:       make(map[string]chan struct{}),
		finalizedTxSet:   make(map[string]struct{}),
	}
}

// Start enters the first iteration.
func (nd *simplexNode) Start() {
	nd.mu.Lock()
	// If the node already advanced past height 1 (e.g. due to receiving
	// messages from peers before Start() was called), do not reset.
	if nd.height > 1 {
		nd.mu.Unlock()
		return
	}
	proposal := nd.enterIterationLocked(1)
	nd.mu.Unlock()
	nd.sendProposal(proposal)
}

// Stop cancels the node.
func (nd *simplexNode) Stop() {
	nd.mu.Lock()
	if nd.timer != nil {
		nd.timer.Stop()
	}
	nd.mu.Unlock()
	nd.cancel()
}

// AddTx enqueues a transaction for the next block this node proposes.
func (nd *simplexNode) AddTx(tx string) {
	nd.txMu.Lock()
	nd.txPool = append(nd.txPool, tx)
	nd.txMu.Unlock()
}

// addTxAndWait enqueues a transaction and blocks until it is finalized,
// the context expires, or the node is stopped.
func (nd *simplexNode) addTxAndWait(ctx context.Context, tx string) error {
	ch := make(chan struct{}, 1)

	nd.pendingTxMu.Lock()
	nd.pendingTxs[tx] = ch
	nd.pendingTxMu.Unlock()

	nd.AddTx(tx)

	return nd.waitForTx(ctx, tx, ch)
}

// registerAndWait registers a pending channel for tx and waits for finalization
// WITHOUT adding the tx to the local pool. Used when the tx is forwarded to the
// leader so the leader's pool is the sole source of the tx.
func (nd *simplexNode) registerAndWait(ctx context.Context, tx string) error {
	ch := make(chan struct{}, 1)

	nd.pendingTxMu.Lock()
	nd.pendingTxs[tx] = ch
	nd.pendingTxMu.Unlock()

	return nd.waitForTx(ctx, tx, ch)
}

func (nd *simplexNode) waitForTx(ctx context.Context, tx string, ch chan struct{}) error {
	select {
	case <-ch:
		return nil
	case <-ctx.Done():
		nd.pendingTxMu.Lock()
		delete(nd.pendingTxs, tx)
		nd.pendingTxMu.Unlock()
		return ctx.Err()
	case <-nd.ctx.Done():
		nd.pendingTxMu.Lock()
		delete(nd.pendingTxs, tx)
		nd.pendingTxMu.Unlock()
		return context.Canceled
	}
}

// signalPendingTxs closes the channels for all finalized transactions.
// Must NOT be called with nd.mu held.
func (nd *simplexNode) signalPendingTxs(txs []string) {
	nd.pendingTxMu.Lock()
	defer nd.pendingTxMu.Unlock()
	for _, tx := range txs {
		nd.finalizedTxSet[tx] = struct{}{}
		if ch, ok := nd.pendingTxs[tx]; ok {
			close(ch)
			delete(nd.pendingTxs, tx)
		}
	}
}

// Height returns the current iteration height.
func (nd *simplexNode) Height() uint64 {
	nd.mu.Lock()
	defer nd.mu.Unlock()
	return nd.height
}

// CurrentLeader returns the node ID of the current iteration's leader.
func (nd *simplexNode) CurrentLeader() uint32 {
	nd.mu.Lock()
	defer nd.mu.Unlock()
	return leaderForHeight(nd.height, nd.n)
}

// FinalizedLog returns all confirmed transactions in height order.
func (nd *simplexNode) FinalizedLog() []string {
	nd.mu.Lock()
	defer nd.mu.Unlock()
	var result []string
	for h := uint64(1); h < nd.height; h++ {
		if txs, ok := nd.finalizedTxs[h]; ok {
			result = append(result, txs...)
		}
	}
	return result
}

// ─── protocol helpers ────────────────────────────────────────────────────────

func quorum(n int) int {
	return (2*n + 2) / 3
}

func leaderForHeight(h uint64, n int) uint32 {
	data := fmt.Appendf(nil, "%d", h)
	hash := sha256.Sum256(data)
	idx := uint64(hash[0]) | uint64(hash[1])<<8 | uint64(hash[2])<<16
	return uint32(idx%uint64(n)) + 1
}

// chainHash returns the parent-hash for a new block: the hash of the most
// recent notarization only (O(1)). Using only the last entry keeps proposals
// small regardless of chain length.
func chainHash(chain []*pb.Notarization) string {
	if len(chain) == 0 {
		return "genesis"
	}
	n := chain[len(chain)-1]
	b := n.GetBlock()
	h := sha256.New()
	fmt.Fprintf(h, "%d|%s|%s|", b.GetHeight(), b.GetParentHash(), strings.Join(b.GetTxs(), ","))
	return fmt.Sprintf("%x", h.Sum(nil))
}

func blockID(b *pb.Block) string {
	if b == nil {
		return ""
	}
	return fmt.Sprintf("%d|%s|%s", b.GetHeight(), b.GetParentHash(), strings.Join(b.GetTxs(), ","))
}

func isDummyBlock(b *pb.Block) bool {
	return b != nil && b.GetHeight() > 0 && b.GetParentHash() == ""
}

// ─── core protocol ───────────────────────────────────────────────────────────

func (nd *simplexNode) enterIterationLocked(h uint64) (proposal *pb.ProposeMsg) {
	nd.height = h
	nd.timerFired = false

	if nd.timer != nil {
		nd.timer.Stop()
	}
	nd.timer = time.AfterFunc(3*delta, func() {
		nd.mu.Lock()
		if nd.height != h || nd.timerFired {
			nd.mu.Unlock()
			return
		}
		nd.timerFired = true
		nd.mu.Unlock()
		nd.doSendVote(h, pb.Block_builder{Height: h}.Build())
	})

	if leaderForHeight(h, nd.n) == nd.id {
		proposal = nd.buildProposalLocked(h)
	}

	nd.processPendingLocked(h)
	return proposal
}

func (nd *simplexNode) buildProposalLocked(h uint64) *pb.ProposeMsg {
	nd.txMu.Lock()
	allTxs := nd.txPool
	nd.txPool = nil
	nd.txMu.Unlock()

	// Filter out txs already finalized by this node (e.g. forwarded duplicates)
	// so they don't consume block space a second time.
	nd.pendingTxMu.Lock()
	txs := make([]string, 0, len(allTxs))
	for _, tx := range allTxs {
		if _, done := nd.finalizedTxSet[tx]; !done {
			txs = append(txs, tx)
		}
	}
	nd.pendingTxMu.Unlock()

	// Save the filtered txs so we can rescue them if a dummy block wins.
	if len(txs) > 0 {
		nd.proposedTxs[h] = txs
	}

	parentHash := chainHash(nd.chain)
	block := pb.Block_builder{
		Height:     h,
		ParentHash: parentHash,
		Txs:        txs,
	}.Build()

	// Do not include the full chain in proposals to avoid unbounded message
	// growth. Receivers verify the parent hash against their own local chain.
	return pb.ProposeMsg_builder{
		Height:   h,
		Block:    block,
		LeaderId: nd.id,
	}.Build()
}

func (nd *simplexNode) sendProposal(msg *pb.ProposeMsg) {
	if msg == nil {
		return
	}
	signPropose(msg, nd.privKey)
	cfgCtx := nd.cfg.Context(nd.ctx)
	if err := pb.Propose(cfgCtx, msg); err != nil && nd.ctx.Err() == nil {
		slog.Warn("propose send error", "node", nd.id, "height", msg.GetHeight(), "err", err)
	}
}

func (nd *simplexNode) advanceFromHeight(h uint64, notarization *pb.Notarization) {
	nd.mu.Lock()
	if nd.height != h {
		nd.mu.Unlock()
		return
	}

	if uint64(len(nd.chain)) < h {
		nd.chain = append(nd.chain, notarization)
	}

	// Send only the new notarization so other nodes can advance one step.
	// Using a single entry keeps the message constant-size.
	newEntry := []*pb.Notarization{notarization}

	proposal := nd.enterIterationLocked(h + 1)
	nd.mu.Unlock()

	nd.sendProposal(proposal)
	nd.doSendFinalize(h)
	nd.doSendNotarizedChain(newEntry)
}

func (nd *simplexNode) processPendingLocked(h uint64) {
	if prop, ok := nd.pendingProposals[h]; ok {
		delete(nd.pendingProposals, h)
		go nd.handlePropose(prop)
	}
	if votes, ok := nd.pendingVotes[h]; ok {
		delete(nd.pendingVotes, h)
		for _, v := range votes {
			go nd.handleVote(v)
		}
	}
}

// ─── outbound senders ────────────────────────────────────────────────────────

func (nd *simplexNode) doSendVote(h uint64, block *pb.Block) {
	msg := pb.VoteMsg_builder{Height: h, Block: block, VoterId: nd.id}.Build()
	signVote(msg, nd.privKey)
	cfgCtx := nd.cfg.Context(nd.ctx)
	if err := pb.Vote(cfgCtx, msg); err != nil && nd.ctx.Err() == nil {
		slog.Warn("vote send error", "node", nd.id, "height", h, "err", err)
	}
}

func (nd *simplexNode) doSendFinalize(h uint64) {
	msg := pb.FinalizeMsg_builder{Height: h, NodeId: nd.id}.Build()
	signFinalize(msg, nd.privKey)
	cfgCtx := nd.cfg.Context(nd.ctx)
	if err := pb.Finalize(cfgCtx, msg); err != nil && nd.ctx.Err() == nil {
		slog.Warn("finalize send error", "node", nd.id, "height", h, "err", err)
	}
}

func (nd *simplexNode) doSendNotarizedChain(chain []*pb.Notarization) {
	msg := pb.NotarizedChainMsg_builder{Chain: chain}.Build()
	cfgCtx := nd.cfg.Context(nd.ctx)
	if err := pb.NotarizedChain(cfgCtx, msg); err != nil && nd.ctx.Err() == nil {
		slog.Warn("chain send error", "node", nd.id, "err", err)
	}
}

// ─── finalization ────────────────────────────────────────────────────────────

// tryFinalizeLocked checks whether height h can be finalized (enough Finalize
// messages AND a notarized block). Returns the confirmed txs or nil.
// Must be called with nd.mu held.
func (nd *simplexNode) tryFinalizeLocked(h uint64) []string {
	if nd.finalized[h] {
		return nil
	}
	if len(nd.finalizes[h]) < quorum(nd.n) {
		return nil
	}
	n, ok := nd.notarized[h]
	if !ok {
		return nil
	}
	nd.finalized[h] = true
	if isDummyBlock(n.GetBlock()) {
		// If this node was the leader and drained its pool for the proposal
		// that lost to the dummy block, rescue those txs back into the pool.
		if rescued, ok := nd.proposedTxs[h]; ok {
			delete(nd.proposedTxs, h)
			nd.txMu.Lock()
			nd.txPool = append(rescued, nd.txPool...)
			nd.txMu.Unlock()
		}
		return nil
	}
	delete(nd.proposedTxs, h)
	txs := n.GetBlock().GetTxs()
	nd.finalizedTxs[h] = txs
	return txs
}

// ─── Gorums RPC handlers ─────────────────────────────────────────────────────

func (nd *simplexNode) Propose(ctx gorums.ServerCtx, req *pb.ProposeMsg) {
	ctx.Release()
	nd.handlePropose(req)
}

func (nd *simplexNode) handlePropose(req *pb.ProposeMsg) {
	h := req.GetHeight()

	leaderID := req.GetLeaderId()
	pub, ok := nd.pubKeys[leaderID]
	if !ok {
		slog.Warn("propose from unknown node", "claimed_leader", leaderID)
		return
	}
	if err := verifyPropose(req, pub); err != nil {
		slog.Warn("propose signature invalid", "err", err)
		return
	}

	nd.mu.Lock()
	if h < nd.height {
		nd.mu.Unlock()
		return
	}
	if h > nd.height {
		if _, exists := nd.pendingProposals[h]; !exists {
			nd.pendingProposals[h] = req
		}
		nd.mu.Unlock()
		return
	}

	if nd.voted[h] {
		nd.mu.Unlock()
		return
	}
	if req.GetLeaderId() != leaderForHeight(h, nd.n) {
		nd.mu.Unlock()
		return
	}
	if req.GetBlock().GetHeight() != h {
		nd.mu.Unlock()
		return
	}
	// Verify the parent hash against this node's own chain. The chain is
	// intentionally not included in proposals (to bound message size) so
	// we derive the expected hash locally.
	expected := chainHash(nd.chain)
	if req.GetBlock().GetParentHash() != expected {
		nd.mu.Unlock()
		return
	}

	nd.voted[h] = true
	block := req.GetBlock()
	nd.mu.Unlock()

	nd.doSendVote(h, block)
}

func (nd *simplexNode) Vote(ctx gorums.ServerCtx, req *pb.VoteMsg) {
	ctx.Release()
	nd.handleVote(req)
}

func (nd *simplexNode) handleVote(req *pb.VoteMsg) {
	h := req.GetHeight()

	voterID := req.GetVoterId()
	pub, ok := nd.pubKeys[voterID]
	if !ok {
		slog.Warn("vote from unknown node", "claimed_voter", voterID)
		return
	}
	if err := verifyVote(req, pub); err != nil {
		slog.Warn("vote signature invalid", "err", err)
		return
	}

	nd.mu.Lock()
	if h < nd.height {
		nd.mu.Unlock()
		return
	}
	if h > nd.height {
		nd.pendingVotes[h] = append(nd.pendingVotes[h], req)
		nd.mu.Unlock()
		return
	}

	bid := blockID(req.GetBlock())
	if nd.votes[h] == nil {
		nd.votes[h] = make(map[string][]*pb.VoteMsg)
	}
	for _, existing := range nd.votes[h][bid] {
		if existing.GetVoterId() == req.GetVoterId() {
			nd.mu.Unlock()
			return
		}
	}
	nd.votes[h][bid] = append(nd.votes[h][bid], req)

	if len(nd.votes[h][bid]) >= quorum(nd.n) {
		if _, already := nd.notarized[h]; !already {
			votes := make([]*pb.VoteMsg, len(nd.votes[h][bid]))
			copy(votes, nd.votes[h][bid])
			notarization := pb.Notarization_builder{
				Block: req.GetBlock(),
				Votes: votes,
			}.Build()
			nd.notarized[h] = notarization
			txs := nd.tryFinalizeLocked(h)
			nd.mu.Unlock()
			if len(txs) > 0 {
				nd.signalPendingTxs(txs)
			}
			nd.advanceFromHeight(h, notarization)
			return
		}
	}
	nd.mu.Unlock()
}

func (nd *simplexNode) Finalize(ctx gorums.ServerCtx, req *pb.FinalizeMsg) {
	ctx.Release()
	nd.handleFinalize(req)
}

func (nd *simplexNode) handleFinalize(req *pb.FinalizeMsg) {
	h := req.GetHeight()
	nodeID := req.GetNodeId()

	pub, ok := nd.pubKeys[nodeID]
	if !ok {
		slog.Warn("finalize from unknown node", "claimed_node", nodeID)
		return
	}
	if err := verifyFinalize(req, pub); err != nil {
		slog.Warn("finalize signature invalid", "err", err)
		return
	}

	nd.mu.Lock()
	if nd.finalized[h] {
		nd.mu.Unlock()
		return
	}
	if nd.finalizes[h] == nil {
		nd.finalizes[h] = make(map[uint32]bool)
	}
	nd.finalizes[h][nodeID] = true
	txs := nd.tryFinalizeLocked(h)
	nd.mu.Unlock()

	if len(txs) > 0 {
		nd.signalPendingTxs(txs)
	}
}

func (nd *simplexNode) NotarizedChain(ctx gorums.ServerCtx, req *pb.NotarizedChainMsg) {
	ctx.Release()
	nd.handleNotarizedChain(req)
}

func (nd *simplexNode) handleNotarizedChain(req *pb.NotarizedChainMsg) {
	incoming := req.GetChain()
	if len(incoming) == 0 {
		return
	}

	for _, notarization := range incoming {
		for _, vote := range notarization.GetVotes() {
			voterID := vote.GetVoterId()
			pub, ok := nd.pubKeys[voterID]
			if !ok {
				slog.Warn("notarized chain contains vote from unknown node", "claimed_voter", voterID)
				return
			}
			if err := verifyVote(vote, pub); err != nil {
				slog.Warn("notarized chain contains invalid vote signature", "err", err)
				return
			}
		}
	}

	// Process each incoming notarization as an incremental step.
	// doSendNotarizedChain now sends a single new entry at a time, so
	// we handle each entry independently rather than replacing the chain.
	for _, notarization := range incoming {
		bh := notarization.GetBlock().GetHeight()

		nd.mu.Lock()
		if nd.height != bh {
			nd.mu.Unlock()
			continue
		}
		// Append to chain at the correct position (chain is 0-indexed, bh is 1-indexed).
		for uint64(len(nd.chain)) < bh-1 {
			nd.chain = append(nd.chain, nil) // gap-fill (shouldn't occur in normal operation)
		}
		if uint64(len(nd.chain)) == bh-1 {
			nd.chain = append(nd.chain, notarization)
		}
		var txsToFinalize []string
		if _, already := nd.notarized[bh]; !already {
			nd.notarized[bh] = notarization
			txsToFinalize = nd.tryFinalizeLocked(bh)
		}
		nd.mu.Unlock()
		if len(txsToFinalize) > 0 {
			nd.signalPendingTxs(txsToFinalize)
		}
		nd.advanceFromHeight(bh, notarization)
	}
}
